external_knowledge:
- "top representative individuals" refers to the representatives with the highest number of appearances;
- "most frequent involvement" indicates the highest count of appearances in the structures;
- "main user" in this context refers to the user with the specific owner_id in the dataset;
- "molecules" refers to molecular structures within the "molecular_structures" table.

- 'Guardians' refer to the representative names;
- 'Hidden molecular treasures' are the molecular structures with high resolution and a large number of nucleotides;
- 'Beyond the veil of public scrutiny' implies that the datasets are private;
- 'Intricate than the average molecular maze' refers to structures with a resolution greater than 1.5 and more than 100 nucleotides.

sql:
SELECT structure_id
FROM molecular_structures
WHERE resolution < 1.0;

SELECT species
FROM molecular_structures
WHERE structure_id = 0;

SELECT structure_id, equivalence_class
FROM molecular_structures
WHERE equivalence_class NOT IN (
  SELECT DISTINCT equivalence_class
  FROM class_members
);

SELECT type, COUNT(*) as NumberOfStructures
FROM molecular_structures
GROUP BY type;

SELECT source 
FROM molecular_structures 
WHERE equivalence_class = 1;

SELECT representative_name 
FROM representatives 
WHERE pdb_id = 2;

SELECT DISTINCT ms.structure_id
FROM molecular_structures ms
JOIN nts n ON ms.nts = n.nts_value;

SELECT DISTINCT species 
FROM molecular_structures 
WHERE source = 'Experimental';

SELECT structure_id, resolution
FROM molecular_structures
WHERE resolution > (SELECT AVG(resolution) FROM molecular_structures);

SELECT structure_id, source
FROM molecular_structures
WHERE type = 'RNA' AND source = 'Computational';

SELECT species, type
FROM molecular_structures
WHERE nts > (
  SELECT AVG(nts)
  FROM molecular_structures
);
